class IdempotencyManager {
  constructor() {
    this._keys = new Map();
    this._cleanupInterval = setInterval(() => this._cleanup(), 60000);
  }

  generateKey(operation, params) {
    const raw = `${operation}:${JSON.stringify(params)}:${Date.now()}`;
    return `idem_${SecurityManager._hashObject({ raw })}`;
  }

  isProcessing(key) {
    const entry = this._keys.get(key);
    if (!entry) return false;
    if (Date.now() > entry.expiresAt) {
      this._keys.delete(key);
      return false;
    }
    return entry.status === 'processing';
  }

  markProcessing(key) {
    this._keys.set(key, {
      status: 'processing',
      startedAt: Date.now(),
      expiresAt: Date.now() + 5 * 60 * 1000,
    });
  }

  markCompleted(key, result) {
    this._keys.set(key, {
      status: 'completed',
      result,
      completedAt: Date.now(),
      expiresAt: Date.now() + 60 * 60 * 1000,
    });
  }

  markFailed(key, error) {
    this._keys.set(key, {
      status: 'failed',
      error: error?.toSafeObject?.() || { message: error?.message },
      failedAt: Date.now(),
      expiresAt: Date.now() + 5 * 60 * 1000,
    });
  }

  getResult(key) {
    const entry = this._keys.get(key);
    if (!entry || Date.now() > entry.expiresAt) return null;
    return entry;
  }

  _cleanup() {
    const now = Date.now();
    for (const [key, entry] of this._keys) {
      if (now > entry.expiresAt) {
        this._keys.delete(key);
      }
    }
  }

  destroy() {
    clearInterval(this._cleanupInterval);
    this._keys.clear();
  }
}

