const PaymentValidator = {
  validateAmount(amount, currency) {
    if (typeof amount !== 'number' || isNaN(amount)) {
      throw new PaymentError(ErrorCodes.INVALID_AMOUNT, 'Amount must be a valid number');
    }
    if (amount < PaymentConfig.MIN_TRANSACTION_AMOUNT) {
      throw new PaymentError(
        ErrorCodes.INVALID_AMOUNT,
        `Amount must be at least ${PaymentConfig.MIN_TRANSACTION_AMOUNT}`
      );
    }
    if (amount > PaymentConfig.MAX_TRANSACTION_AMOUNT) {
      throw new PaymentError(
        ErrorCodes.INVALID_AMOUNT,
        `Amount cannot exceed ${PaymentConfig.MAX_TRANSACTION_AMOUNT}`
      );
    }
    if (!PaymentConfig.SUPPORTED_CURRENCIES.includes(currency)) {
      throw new PaymentError(
        ErrorCodes.INVALID_CURRENCY,
        `Currency ${currency} is not supported`
      );
    }
    return true;
  },

  validateCardNumber(number) {
    const cleaned = number.replace(/\s|-/g, '');
    if (!/^\d{13,19}$/.test(cleaned)) {
      throw new PaymentError(ErrorCodes.INVALID_CARD, 'Invalid card number format');
    }
    // Luhn algorithm
    let sum = 0;
    let isEven = false;
    for (let i = cleaned.length - 1; i >= 0; i--) {
      let digit = parseInt(cleaned[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }
    if (sum % 10 !== 0) {
      throw new PaymentError(ErrorCodes.INVALID_CARD, 'Invalid card number');
    }
    return true;
  },

  validateExpiry(month, year) {
    const m = parseInt(month, 10);
    const y = parseInt(year, 10);
    if (isNaN(m) || isNaN(y) || m < 1 || m > 12) {
      throw new PaymentError(ErrorCodes.INVALID_CARD, 'Invalid expiry date');
    }
    const now = new Date();
    const currentYear = now.getFullYear() % 100;
    const currentMonth = now.getMonth() + 1;
    const fullYear = y < 100 ? y : y % 100;
    if (fullYear < currentYear || (fullYear === currentYear && m < currentMonth)) {
      throw new PaymentError(ErrorCodes.INVALID_CARD, 'Card has expired');
    }
    return true;
  },

  validateCVV(cvv) {
    if (!/^\d{3,4}$/.test(cvv)) {
      throw new PaymentError(ErrorCodes.INVALID_CARD, 'Invalid CVV');
    }
    return true;
  },

  getCardType(number) {
    const cleaned = number.replace(/\s|-/g, '');
    if (/^4/.test(cleaned)) return 'visa';
    if (/^5[1-5]/.test(cleaned) || /^2[2-7]/.test(cleaned)) return 'mastercard';
    if (/^3[47]/.test(cleaned)) return 'amex';
    if (/^6(?:011|5)/.test(cleaned)) return 'discover';
    if (/^35/.test(cleaned)) return 'jcb';
    if (/^3(?:0[0-5]|[68])/.test(cleaned)) return 'diners';
    return 'unknown';
  },
};

