class PaymentAPIClient {
  constructor() {
    this.rateLimiter = new RateLimiter(20, 60000);
    this.idempotency = new IdempotencyManager();
    this._authToken = null;
    this._session = null;
  }

  async initialize(authToken) {
    this._authToken = authToken;
    this._session = await SecurityManager.createSecureSession();
    AuditLogger.log('API_CLIENT_INITIALIZED', { sessionId: this._session.sessionId });
  }

  async request(method, endpoint, body = null, options = {}) {
    if (!this.rateLimiter.canProceed()) {
      const retryAfter = this.rateLimiter.getRetryAfter();
      throw new PaymentError(
        ErrorCodes.RATE_LIMITED,
        `Rate limited. Retry after ${retryAfter}ms`
      );
    }

    if (this._session && !SecurityManager.isSessionValid(this._session)) {
      this._session = await SecurityManager.createSecureSession();
    }

    const idempotencyKey = options.idempotencyKey || this.idempotency.generateKey(endpoint, body);

    const existingResult = this.idempotency.getResult(idempotencyKey);
    if (existingResult?.status === 'completed') {
      return existingResult.result;
    }
    if (existingResult?.status === 'processing') {
      throw new PaymentError(
        ErrorCodes.DUPLICATE_TRANSACTION,
        'Transaction is already being processed'
      );
    }

    this.idempotency.markProcessing(idempotencyKey);

    const headers = {
      'Content-Type': 'application/json',
      'X-Idempotency-Key': idempotencyKey,
      'X-Session-Id': this._session?.sessionId || '',
      'X-Platform': Platform.OS,
      'X-Platform-Version': String(Platform.Version),
      'X-Request-Nonce': SecurityManager.generateNonce(),
    };

    if (this._authToken) {
      headers['Authorization'] = `Bearer ${this._authToken}`;
    }

    const controller = new AbortController();
    const timeout = setTimeout(
      () => controller.abort(),
      options.timeout || PaymentConfig.TRANSACTION_TIMEOUT_MS
    );

    let lastError;
    const maxRetries = options.retries ?? PaymentConfig.MAX_RETRY_ATTEMPTS;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        const response = await fetch(`${PaymentConfig.API_BASE_URL}${endpoint}`, {
          method,
          headers,
          body: body ? JSON.stringify(body) : null,
          signal: controller.signal,
        });

        clearTimeout(timeout);

        if (!response.ok) {
          const errorBody = await response.json().catch(() => ({}));

          if (response.status === 429) {
            throw new PaymentError(ErrorCodes.RATE_LIMITED, 'Server rate limit exceeded');
          }
          if (response.status >= 500) {
            throw new PaymentError(ErrorCodes.SERVER_ERROR, errorBody.message || 'Server error');
          }

          const error = new PaymentError(
            errorBody.code || 'API_ERROR',
            errorBody.message || `HTTP ${response.status}`
          );
          this.idempotency.markFailed(idempotencyKey, error);
          throw error;
        }

        const result = await response.json();
        this.idempotency.markCompleted(idempotencyKey, result);
        return result;
      } catch (error) {
        lastError = error;

        if (error instanceof PaymentError && !error.isRetryable) {
          this.idempotency.markFailed(idempotencyKey, error);
          throw error;
        }

        if (error.name === 'AbortError') {
          const timeoutError = new PaymentError(ErrorCodes.TIMEOUT, 'Request timed out');
          this.idempotency.markFailed(idempotencyKey, timeoutError);
          throw timeoutError;
        }

        if (attempt < maxRetries) {
          const delay = PaymentConfig.RETRY_DELAY_MS * Math.pow(2, attempt);
          await new Promise((resolve) => setTimeout(resolve, delay));
          continue;
        }
      }
    }

    clearTimeout(timeout);
    const finalError =
      lastError instanceof PaymentError
        ? lastError
        : new PaymentError(ErrorCodes.NETWORK_ERROR, 'Network request failed', lastError);
    this.idempotency.markFailed(idempotencyKey, finalError);
    throw finalError;
  }

  destroy() {
    this.idempotency.destroy();
  }
}

